CREATE TABLE t_p33849287_desinsect_service_ma.documents (id SERIAL PRIMARY KEY, doc_number VARCHAR(50) UNIQUE NOT NULL, type VARCHAR(20) DEFAULT 'estimate', client_id INTEGER, client_name VARCHAR(255), order_id INTEGER, issue_date DATE DEFAULT CURRENT_DATE, due_date DATE, status VARCHAR(20) DEFAULT 'draft', items JSONB DEFAULT '[]', created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW());